{
  "name": "Senior Citizen E-ZPass Discount",
  "eligibility": {
    "age": 65,
    "income_limits": "No income limits or asset limits apply. Eligibility is not based on income, assets, or household size.",
    "asset_limits": "No asset limits. No requirements for what counts or exemptions.",
    "other_requirements": ["Must have an active New Jersey E-ZPass account.", "Must have a valid driver's license issued by any state.", "Must have a passenger vehicle registered in your name or your spouse's name in any state (leasing requires proof of lessee status).", "Must be the driver in the vehicle at the time of toll transaction.", "Vehicle registration can be in NJ, PA, or DE for DRPA bridges.", "Only one E-ZPass tag/transponder per senior (must start with 009 or 022).", "Business/commercial accounts ineligible.", "Renewal required annually, aligned with vehicle registration renewal date."]
  },
  "benefits": {
    "type": "financial",
    "value": "10% discount on off-peak tolls on New Jersey Turnpike and Garden State Parkway (weekdays off-peak and weekends); off-peak only, passenger vehicles. Separate DRPA Senior Discount for Benjamin Franklin, Walt Whitman, Betsy Ross, and Commodore Barry bridges (credit of $18 for 18+ trips in a calendar month).",
    "varies_by": "fixed"
  },
  "application": {
    "methods": ["Online: https://seniordiscount.njta.gov (NJTA Turnpike/GSP); www.ezpassnj.com for new NJ E-ZPass account.", "Phone: 1-888-288-6865 (new NJ E-ZPass account); 732-750-5300 (enroll in NJTA Senior Plan); 856-968-2000 press 5 or 215-218-3750 press 5 (DRPA Senior Plan).", "Mail: P.O. Box 5042, Woodbridge, NJ 07095.", "In-person: E-ZPass Customer Service Centers (locations at www.ezpassnj.com)."],
    "processing_time": "Not specified in sources.",
    "waitlist": null,
    "forms": ["NJTA Senior Citizen Discount Program for E-ZPass Application (online at https://seniordiscount.njta.gov)."],
    "documents": ["Copy of valid driver's license (to prove age 65+; no other ID accepted).", "Copy of passenger vehicle registration (in your name or spouse's).", "If leasing: Top portion of lease agreement showing you as lessee.", "NJ E-ZPass Account # (13 digits).", "E-ZPass Tag/Transponder # (11 digits)."]
  },
  "geography": {
    "statewide": true,
    "restrictions": "NJ E-ZPass account required; applies to NJ Turnpike, Garden State Parkway statewide; DRPA for specific bridges (NJ-PA-DE registered vehicles). No residency requirement.",
    "regional_variations": "Separate DRPA program for four bridges with different enrollment phone numbers; no other regional differences noted.",
    "offices_or_providers": ["NJ Turnpike Authority (NJTA) for Turnpike/GSP.", "Delaware River Port Authority (DRPA) for bridges."]
  },
  "official_source": "https://seniordiscount.njta.gov and https://www.ezpassnj.com/en/about/plans.shtml",
  "gotchas": ["Must be the eligible senior driving the vehicle (not just passenger).", "Tag-specific: Only one tag per senior; misuse by others revokes privileges.", "Off-peak only (no peak hours, no commercial vehicles).", "Annual renewal required, timed to vehicle registration date (may be less than 12 months).", "Must have NJ E-ZPass account (statements from Newark, NJ); out-of-state residents can open one.", "DRPA is separate program with its own rules and $18 monthly credit threshold."],
  "data_shape_notes": "No income/asset test; tag-specific and driver-present requirements; separate DRPA bridge program; annual renewal tied to vehicle registration."
}
